package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP13LoginCamareroExitosoPlaywrightTest extends BaseTestPlaywright {    @Test    void loginCamareroExitoso() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("camarero");        page.locator("input[name='password']")                .fill("123");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        String contenido = page.content();        assertTrue(                contenido.contains("Crear pedido")                        || contenido.contains("Pedidos Actuales")                        || contenido.contains("Pre-Boleta"),                "El Panel Camarero no se muestra después del inicio de sesión."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP13-login-camarero-exitoso.png"))                        .setFullPage(true)        );    }}